package mod.fuji.module.initializer.skin.config.model;

import mod.fuji.core.document.annotation.Document;

import mod.fuji.core.config.mapper.wrapper.PropertyIR;
import mod.fuji.module.initializer.skin.structure.SkinDescriptor;
import java.util.ArrayList;
import java.util.List;
import lombok.Data;
import lombok.NoArgsConstructor;

@Data
@NoArgsConstructor
public class SkinConfigModel {

    DefaultSkin defaultSkin = new DefaultSkin();

    @Data
    @NoArgsConstructor
    public static class DefaultSkin {

        @Document(id = 1753269459208L, value = """
            If this option is `true`, then for a player who doesn't have existing `skin` data, the `default skin` will be applied.
            If this option is `false`, then the `Mojang online skin` will be applied instead.
            """)
        boolean applyDefaultSkinIfNoData = false;

        @Document(id = 1753268443704L, value = """
            Specify a `preferred skin` in the `default skin list`, so it will be the `default skin`.
            If you specify a `invalid skin name` or this option is `null`, then a `random` skin will be picked from the `default skin list`.
            """)
        String preferredSkinName = "reimu-hakurei";

        @Document(id = 1751826804319L, value = """
        The defined `default skins` for this server.
        """)
        List<SkinDescriptor> defaultSkinList = new ArrayList<>() {
            {
                this.add(new SkinDescriptor("reimu-hakurei", new PropertyIR("textures", "", "")));
                this.add(new SkinDescriptor("remilia-scarlet", new PropertyIR("textures", "", "")));
                this.add(new SkinDescriptor("koishi-komeiji", new PropertyIR("textures", "", "")));
            }
        };
    }

}
